import{_ as p,c as s}from"./app.0b00aae6.js";const o={},e=s('<h1 id="_05-\u8BB2-\u4F60\u77E5\u9053\u8F6F\u4EF6\u5F00\u53D1\u5404\u9636\u6BB5\u90FD\u6709\u54EA\u4E9B\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u5417" tabindex="-1"><a class="header-anchor" href="#_05-\u8BB2-\u4F60\u77E5\u9053\u8F6F\u4EF6\u5F00\u53D1\u5404\u9636\u6BB5\u90FD\u6709\u54EA\u4E9B\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u5417" aria-hidden="true">#</a> 05 \u8BB2\uFF1A\u4F60\u77E5\u9053\u8F6F\u4EF6\u5F00\u53D1\u5404\u9636\u6BB5\u90FD\u6709\u54EA\u4E9B\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u5417\uFF1F</h1><p>\u5728\u524D\u9762\u7684\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECB\u7ECD\u4E86\u4E3A\u4EC0\u4E48\u8981\u505A\u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u4EE5\u53CA\u4EC0\u4E48\u6837\u7684\u9879\u76EE\u9002\u5408\u505A\u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u90A3\u4E48\u73B0\u5728\u6211\u6765\u8BF4\u8BF4\u8F6F\u4EF6\u5F00\u53D1\u751F\u547D\u5468\u671F\u7684\u5404\u4E2A\u9636\u6BB5\u90FD\u6709\u54EA\u4E9B\u7C7B\u578B\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u3002</p><p>\u8BF4\u5230\u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u4F60\u53EF\u80FD\u6700\u4E3A\u719F\u6089\u7684\u5C31\u662F GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u4E86\u3002\u6BD4\u5982\uFF0C\u65E9\u5E74\u7684 C/S \u67B6\u6784\uFF0C\u901A\u5E38\u5C31\u662F\u7528\u81EA\u52A8\u5316\u6D4B\u8BD5\u811A\u672C\u6253\u5F00\u88AB\u6D4B\u5E94\u7528\uFF0C\u7136\u540E\u5728\u754C\u9762\u4E0A\u4EE5\u81EA\u52A8\u5316\u7684\u65B9\u5F0F\u6267\u884C\u4E00\u7CFB\u5217\u7684\u64CD\u4F5C\uFF1B\u518D\u6BD4\u5982\uFF0C\u73B0\u4ECA\u7684 Web \u7AD9\u70B9\u6D4B\u8BD5\uFF0C\u4E5F\u662F\u7528\u81EA\u52A8\u5316\u6D4B\u8BD5\u811A\u672C\u6253\u5F00\u6D4F\u89C8\u5668\uFF0C\u7136\u540E\u8F93\u5165\u8981\u8BBF\u95EE\u7684\u7F51\u5740\uFF0C\u4E4B\u540E\u7528\u81EA\u52A8\u5316\u811A\u672C\u8BC6\u522B\u5B9A\u4F4D\u9875\u9762\u5143\u7D20\uFF0C\u5E76\u8FDB\u884C\u76F8\u5E94\u7684\u64CD\u4F5C\u3002</p><p>\u56E0\u6B64\uFF0C\u8BF4\u5230\u81EA\u52A8\u5316\u6D4B\u8BD5\u65F6\uFF0C\u4F60\u7684\u7B2C\u4E00\u53CD\u5E94\u5F88\u53EF\u80FD\u5C31\u662F GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u3002\u7136\u800C\uFF0C<strong>\u5728\u8F6F\u4EF6\u7814\u53D1\u751F\u547D\u5468\u671F\u7684\u5404\u4E2A\u9636\u6BB5\u90FD\u6709\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u7684\u5B58\u5728\uFF0C\u5E76\u4E14\u5BF9\u63D0\u5347\u6D4B\u8BD5\u6548\u7387\u6709\u7740\u81F3\u5173\u91CD\u8981\u7684\u4F5C\u7528</strong>\u3002</p><p>\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u6211\u5C06\u4F1A\u4EE5\u4E0D\u540C\u7684\u8F6F\u4EF6\u5F00\u53D1\u9636\u6BB5\u6D89\u53CA\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u4E3A\u4E3B\u7EBF\uFF0C\u5E26\u4F60\u4E86\u89E3\u5355\u5143\u6D4B\u8BD5\u3001\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u3001Web Service \u6D4B\u8BD5\u548C GUI \u6D4B\u8BD5\u9636\u6BB5\u7684\u81EA\u52A8\u5316\u6280\u672F\uFF0C\u5E0C\u671B\u53EF\u4EE5\u5E2E\u52A9\u4F60\u66F4\u6DF1\u5165\u5730\u7406\u89E3\u201C\u81EA\u52A8\u5316\u6D4B\u8BD5\u201D\u7684\u5185\u6DB5\u4EE5\u53CA\u5916\u5EF6\u3002</p><p><strong>\u5355\u5143\u6D4B\u8BD5\u7684\u81EA\u52A8\u5316\u6280\u672F</strong></p><p>\u9996\u5148\uFF0C\u4F60\u53EF\u80FD\u8BA4\u4E3A\u5355\u5143\u6D4B\u8BD5\u672C\u8EAB\u5C31\u662F\u81EA\u52A8\u5316\u7684\uFF0C\u56E0\u4E3A\u5B83\u6839\u636E\u8F6F\u4EF6\u8BE6\u7EC6\u8BBE\u8BA1\u91C7\u7528\u7B49\u4EF7\u7C7B\u5212\u5206\u548C\u8FB9\u754C\u503C\u5206\u6790\u65B9\u6CD5\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5728\u6D4B\u8BD5\u4EE3\u7801\u5B9E\u73B0\u540E\u518D\u4EE5\u81EA\u52A8\u5316\u7684\u65B9\u5F0F\u7EDF\u4E00\u6267\u884C\u3002</p><p>\u8FD9\u4E2A\u89C2\u70B9\u975E\u5E38\u6B63\u786E\uFF0C\u4F46\u8FD9\u4EC5\u4EC5\u662F\u4E00\u90E8\u5206\uFF0C\u5E76\u6CA1\u6709\u5B8C\u6574\u5730\u63CF\u8FF0\u5355\u5143\u6D4B\u8BD5\u201C\u81EA\u52A8\u5316\u201D\u7684\u5185\u6DB5\u3002<strong>\u4ECE\u5E7F\u4E49\u4E0A\u8BB2\uFF0C\u5355\u5143\u6D4B\u8BD5\u9636\u6BB5\u7684\u201C\u81EA\u52A8\u5316\u201D\u5185\u6DB5\u4E0D\u4EC5\u4EC5\u6307\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u81EA\u52A8\u5316\uFF0C\u8FD8\u5E94\u8BE5\u5305\u542B\u4EE5\u4E0B\u4E94\u4E2A\u65B9\u9762\uFF1A</strong></p><ol><li>\u7528\u4F8B\u6846\u67B6\u4EE3\u7801\u751F\u6210\u7684\u81EA\u52A8\u5316\uFF1B</li><li>\u90E8\u5206\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u7684\u81EA\u52A8\u5316\u751F\u6210\uFF1B</li><li>\u81EA\u52A8\u6869\u4EE3\u7801\u7684\u751F\u6210\uFF1B</li><li>\u88AB\u6D4B\u4EE3\u7801\u7684\u81EA\u52A8\u5316\u9759\u6001\u5206\u6790\uFF1B</li><li>\u6D4B\u8BD5\u8986\u76D6\u7387\u7684\u81EA\u52A8\u7EDF\u8BA1\u4E0E\u5206\u6790\u3002</li></ol><p>\u4F60\u53EF\u80FD\u611F\u89C9\u8FD9\u4E9B\u5185\u5BB9\u6709\u4E9B\u964C\u751F\uFF0C\u4E0D\u8FC7\u6CA1\u5173\u7CFB\uFF0C\u4E0B\u9762\u6211\u5C31\u8BE6\u7EC6\u5730\u8DDF\u4F60\u8BF4\u8BF4\u6BCF\u4E00\u6761\u7684\u5177\u4F53\u542B\u4E49\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u7528\u4F8B\u6846\u67B6\u4EE3\u7801\u751F\u6210\u7684\u81EA\u52A8\u5316</strong></p><p>\u6709\u4E9B\u6846\u67B6\u4EE3\u7801\u5E94\u8BE5\u7531\u81EA\u52A8\u5316\u5DE5\u5177\u751F\u6210\uFF0C\u800C\u4E0D\u662F\u7531\u5F00\u53D1\u8005\u624B\u5DE5\u5B8C\u6210\u3002\u8FD9\u6837\u4E00\u6765\uFF0C\u5355\u5143\u6D4B\u8BD5\u5F00\u53D1\u8005\u53EF\u4EE5\u628A\u66F4\u591A\u7684\u7CBE\u529B\u653E\u5728\u6D4B\u8BD5\u903B\u8F91\u7684\u8986\u76D6\u548C\u6D4B\u8BD5\u6570\u636E\u7684\u9009\u62E9\u4E0A\uFF0C\u4ECE\u800C\u5927\u5E45\u63D0\u9AD8\u5355\u5143\u6D4B\u8BD5\u7528\u4F8B\u7684\u8D28\u91CF\u548C\u5F00\u53D1\u6548\u7387\u3002 <img src="https://static001.geekbang.org/resource/image/48/4a/4824e7700dfc20db4808557d254d4a4a.png" alt="TestNG\u6846\u67B6\u4EE3\u7801\u5E94\u8BE5\u7531\u81EA\u52A8\u5316\u5DE5\u5177\u751F\u6210"></p><p><strong>\u7B2C\u4E8C\uFF0C\u90E8\u5206\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u7684\u81EA\u52A8\u5316\u751F\u6210</strong></p><p>\u8FD9\u90E8\u5206\u662F\u6307\uFF0C\u81EA\u52A8\u5316\u5DE5\u5177\u80FD\u591F\u6839\u636E\u4E0D\u540C\u53D8\u91CF\u7C7B\u578B\u81EA\u52A8\u751F\u6210\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u3002\u81EA\u52A8\u5316\u5DE5\u5177\u672C\u8EAB\u4E0D\u53EF\u80FD\u660E\u767D\u4EE3\u7801\u903B\u8F91\uFF0C\u4F60\u53EF\u80FD\u5F88\u96BE\u7406\u89E3\u5B83\u662F\u5982\u4F55\u6839\u636E\u9700\u8981\u6D4B\u8BD5\u7684\u4EE3\u7801\u903B\u8F91\u751F\u6210\u5408\u9002\u7684\u8F93\u5165\u6570\u636E\uFF0C\u5E76\u4E14\u53BB\u5224\u65AD\u9884\u8BA1\u7684\u6D4B\u8BD5\u7ED3\u679C\u7684\u3002\u90A3\u6211\u7ED9\u4F60\u4E3E\u4E2A\u4F8B\u5B50\uFF0C\u4F60\u5C31\u5F88\u5BB9\u6613\u660E\u767D\u4E86\u3002</p><p>\u6BD4\u5982\uFF0C\u67D0\u4E2A\u88AB\u6D4B\u51FD\u6570\u7684\u539F\u578B\u662F void fun\uFF08int* p, short b\uFF09\uFF0C\u90A3\u4E48\u6D4B\u8BD5\u6570\u636E\u81EA\u52A8\u751F\u6210\u6280\u672F\u5C31\u4F1A\u4E3A\u8F93\u5165\u53C2\u6570 int* p \u81EA\u52A8\u751F\u6210\u201C\u7A7A\u201D\u548C\u201C\u975E\u7A7A\u201D\u7684\u4E24\u4E2A\u6307\u9488 p\uFF0C\u7136\u540E\u5206\u522B\u6267\u884C\u51FD\u6570 void fun\uFF08int* p, short b\uFF09\uFF0C\u5E76\u89C2\u5BDF\u51FD\u6570\u7684\u6267\u884C\u60C5\u51B5\u3002</p><p>\u5982\u679C\u51FD\u6570\u5185\u90E8\u6CA1\u6709\u5BF9\u7A7A\u6307\u9488\u8FDB\u884C\u7279\u6B8A\u5904\u7406\uFF0C\u90A3\u4E48\u51FD\u6570 fun \u7684\u8C03\u7528\u5FC5\u5B9A\u4F1A\u629B\u51FA\u5F02\u5E38\uFF0C\u4ECE\u800C\u53D1\u73B0\u51FD\u6570\u7684\u8BBE\u8BA1\u7F3A\u9677\u3002\u540C\u6837\u5730\uFF0C\u5BF9\u4E8E\u8F93\u5165\u53C2\u6570 short b \u4F1A\u81EA\u52A8\u751F\u6210\u8D85\u51FA short \u8303\u56F4\u7684 b\uFF0C\u6D4B\u8BD5\u51FD\u6570 fun \u7684\u884C\u4E3A\u3002</p><p><strong>\u7B2C\u4E09\uFF0C\u81EA\u52A8\u6869\u4EE3\u7801\u7684\u751F\u6210</strong></p><p><strong>\u7B80\u5355\u5730\u8BF4\uFF0C\u6869\u4EE3\u7801\uFF08stub code\uFF09\u662F\u7528\u6765\u4EE3\u66FF\u771F\u5B9E\u4EE3\u7801\u7684\u4E34\u65F6\u4EE3\u7801</strong>\u3002 \u6BD4\u5982\uFF0C\u67D0\u4E2A\u51FD\u6570 A \u7684\u5185\u90E8\u5B9E\u73B0\u4E2D\u8C03\u7528\u4E86\u4E00\u4E2A\u5C1A\u672A\u5B9E\u73B0\u7684\u51FD\u6570 B\uFF0C\u4E3A\u4E86\u5BF9\u51FD\u6570 A \u7684\u903B\u8F91\u8FDB\u884C\u6D4B\u8BD5\uFF0C\u90A3\u4E48\u5C31\u9700\u8981\u6A21\u62DF\u4E00\u4E2A\u51FD\u6570 B\uFF0C\u8FD9\u4E2A\u6A21\u62DF\u7684\u51FD\u6570 B \u5B9E\u73B0\u5C31\u662F\u6240\u8C13\u7684\u6869\u4EE3\u7801\u3002</p><p>\u81EA\u52A8\u6869\u4EE3\u7801\u7684\u751F\u6210\u662F\u6307\u81EA\u52A8\u5316\u5DE5\u5177\u53EF\u4EE5\u5BF9\u88AB\u6D4B\u8BD5\u4EE3\u7801\u8FDB\u884C\u626B\u63CF\u5206\u6790\uFF0C\u81EA\u52A8\u4E3A\u88AB\u6D4B\u51FD\u6570\u5185\u90E8\u8C03\u7528\u7684\u5176\u4ED6\u51FD\u6570\u751F\u6210\u53EF\u7F16\u7A0B\u7684\u6869\u4EE3\u7801\uFF0C\u5E76\u63D0\u4F9B\u57FA\u4E8E\u6D4B\u8BD5\u7528\u4F8B\u7684\u6869\u4EE3\u7801\u7BA1\u7406\u673A\u5236\u3002\u6B64\u65F6\uFF0C<strong>\u5355\u5143\u6D4B\u8BD5\u5F00\u53D1\u8005\u53EA\u9700\u91CD\u70B9\u5173\u6CE8\u6869\u4EE3\u7801\u5185\u7684\u5177\u4F53\u903B\u8F91\u5B9E\u73B0\uFF0C\u4EE5\u53CA\u6869\u4EE3\u7801\u7684\u8FD4\u56DE\u503C</strong>\u3002</p><p>\u5FC5\u8981\u7684\u65F6\u5019\uFF0C\u81EA\u52A8\u5316\u5DE5\u5177\u8FD8\u9700\u8981\u5B9E\u73B0 \u201C\u62BD\u6869\u201D\uFF0C\u4EE5\u9002\u5E94\u540E\u7EED\u7684\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u7684\u9700\u6C42\u3002</p><p>\u90A3\u4EC0\u4E48\u662F\u201C\u62BD\u6869\u201D\u5462\uFF1F\u5176\u5B9E\u4E5F\u5F88\u7B80\u5355\uFF0C\u5728\u5355\u5143\u6D4B\u8BD5\u9636\u6BB5\uFF0C\u5047\u5982\u51FD\u6570 A \u5185\u90E8\u8C03\u7528\u7684\u51FD\u6570 B \u662F\u6869\u4EE3\u7801\uFF0C\u90A3\u4E48\u5728\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u9636\u6BB5\uFF0C\u6211\u4EEC\u5E0C\u671B\u51FD\u6570 A \u4E0D\u518D\u8C03\u7528\u5047\u7684\u51FD\u6570 B\uFF0C\u800C\u662F\u8C03\u7528\u771F\u5B9E\u7684\u51FD\u6570 B\uFF0C\u8FD9\u4E2A\u7528\u771F\u5B9E\u51FD\u6570 B \u4EE3\u66FF\u539F\u672C\u6869\u4EE3\u7801\u51FD\u6570 B \u7684\u64CD\u4F5C\uFF0C\u5C31\u79F0\u4E3A\u201C\u62BD\u6869\u201D\u3002</p><p><strong>\u7B2C\u56DB\uFF0C\u88AB\u6D4B\u4EE3\u7801\u7684\u81EA\u52A8\u5316\u9759\u6001\u5206\u6790</strong></p><p>\u9759\u6001\u5206\u6790\u4E3B\u8981\u6307\u4EE3\u7801\u7684\u9759\u6001\u626B\u63CF\uFF0C\u76EE\u7684\u662F\u8BC6\u522B\u51FA\u8FDD\u53CD\u7F16\u7801\u89C4\u5219\u6216\u7F16\u7801\u98CE\u683C\u7684\u4EE3\u7801\u884C\u3002\u901A\u5E38\u8FD9\u90E8\u5206\u5DE5\u4F5C\u662F\u7ED3\u5408\u9879\u76EE\u5177\u4F53\u7684\u7F16\u7801\u89C4\u5219\u548C\u7F16\u7801\u98CE\u683C\uFF0C\u7531\u81EA\u52A8\u5316\u5DE5\u5177\u901A\u8FC7\u5185\u5EFA\u89C4\u5219\u548C\u7528\u6237\u81EA\u5B9A\u4E49\u89C4\u5219\u81EA\u52A8\u5316\u5B8C\u6210\u7684\u3002\u76EE\u524D\u6BD4\u8F83\u5E38\u7528\u7684\u4EE3\u7801\u9759\u6001\u5206\u6790\u5DE5\u5177\u6709 Sonar \u548C Coverity \u7B49\u3002</p><p>\u4E25\u683C\u610F\u4E49\u4E0A\u8BB2\uFF0C\u9759\u6001\u5206\u6790\u4E0D\u5C5E\u4E8E\u5355\u5143\u6D4B\u8BD5\u7684\u8303\u7574\uFF0C\u4F46\u8FD9\u90E8\u5206\u5DE5\u4F5C\u4E00\u822C\u662F\u5728\u5355\u5143\u6D4B\u8BD5\u9636\u6BB5\u901A\u8FC7\u81EA\u52A8\u5316\u5DE5\u5177\u5B8C\u6210\u7684\uFF0C\u6240\u4EE5\u6211\u4E5F\u628A\u5B83\u5F52\u5165\u5230\u4E86\u5355\u5143\u6D4B\u8BD5\u81EA\u52A8\u5316\u7684\u8303\u7574\u3002</p><p><strong>\u7B2C\u4E94\uFF0C\u6D4B\u8BD5\u8986\u76D6\u7387\u7684\u81EA\u52A8\u7EDF\u8BA1\u4E0E\u5206\u6790</strong></p><p>\u5355\u5143\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7ED3\u675F\u540E\uFF0C\u81EA\u52A8\u5316\u5DE5\u5177\u53EF\u4EE5\u81EA\u52A8\u7EDF\u8BA1\u5404\u79CD\u6D4B\u8BD5\u8986\u76D6\u7387\uFF0C\u5305\u62EC\u4EE3\u7801\u884C\u8986\u76D6\u7387\u3001\u5206\u652F\u8986\u76D6\u7387\u3001MC/DC \u8986\u76D6\u7387\u7B49\u3002\u8FD9\u4E9B\u81EA\u52A8\u7EDF\u8BA1\u7684\u6307\u6807\uFF0C\u53EF\u4EE5\u5E2E\u4F60\u8861\u91CF\u5355\u5143\u6D4B\u8BD5\u7528\u4F8B\u96C6\u5408\u7684\u5145\u5206\u6027\u548C\u5B8C\u5907\u6027\uFF0C\u5E76\u53EF\u4EE5\u4E3A\u4F60\u63D0\u4F9B\u9002\u5F53\u589E\u8865\u6D4B\u8BD5\u7528\u4F8B\u4EE5\u63D0\u9AD8\u6D4B\u8BD5\u8986\u76D6\u7387\u7684\u4F9D\u636E\u3002</p><p><strong>\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u7684\u81EA\u52A8\u5316\u6280\u672F</strong></p><p>\u901A\u4FD7\u5730\u8BB2\uFF0C\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u662F\u6307\u5C06\u5DF2\u7ECF\u5F00\u53D1\u5B8C\u6210\u7684\u8F6F\u4EF6\u6A21\u5757\u653E\u5728\u4E00\u8D77\u6D4B\u8BD5\u3002</p><p>\u4ECE\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u548C\u6D4B\u8BD5\u4EE3\u7801\u7ED3\u6784\u6765\u770B\uFF0C\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u548C\u5355\u5143\u6D4B\u8BD5\u975E\u5E38\u76F8\u4F3C\uFF0C\u5B83\u4EEC\u90FD\u662F\u5BF9\u88AB\u6D4B\u8BD5\u51FD\u6570\u4EE5\u4E0D\u540C\u7684\u8F93\u5165\u53C2\u6570\u7EC4\u5408\u8FDB\u884C\u8C03\u7528\u5E76\u9A8C\u8BC1\u7ED3\u679C\uFF0C\u53EA\u4E0D\u8FC7\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u7684\u5173\u6CE8\u70B9\uFF0C\u66F4\u591A\u7684\u662F\u8F6F\u4EF6\u6A21\u5757\u4E4B\u95F4\u7684\u63A5\u53E3\u8C03\u7528\u548C\u6570\u636E\u4F20\u9012\u3002</p><p><em>\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u4E0E\u5355\u5143\u6D4B\u8BD5\u6700\u5927\u7684\u533A\u522B\u53EA\u662F\uFF0C\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u4E2D\u88AB\u6D4B\u51FD\u6570\u5185\u90E8\u8C03\u7528\u7684\u5176\u4ED6\u51FD\u6570\u5FC5\u987B\u662F\u771F\u5B9E\u7684\uFF0C\u4E0D\u5141\u8BB8\u4F7F\u7528\u6869\u4EE3\u7801\u4EE3\u66FF\uFF0C\u800C\u5355\u5143\u6D4B\u8BD5\u4E2D\u5141\u8BB8\u4F7F\u7528\u6869\u4EE3\u7801\u6765\u6A21\u62DF\u5185\u90E8\u8C03\u7528\u7684\u5176\u4ED6\u51FD\u6570</em>\u3002</p><p>\u4EE5\u4E0A\u7684\u8FD9\u4E9B\u5F02\u540C\u70B9\u5C31\u51B3\u5B9A\u4E86\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u201C\u81EA\u52A8\u5316\u201D\u7684\u5185\u6DB5\u4E0E\u5355\u5143\u6D4B\u8BD5\u975E\u5E38\u76F8\u4F3C\uFF0C\u5C24\u5176\u662F\u5728\u5B9E\u9645\u64CD\u4F5C\u5C42\u9762\uFF0C\u6BD4\u5982\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\u65B9\u6CD5\u3001\u6D4B\u8BD5\u7528\u4F8B\u7684\u4EE3\u7801\u7ED3\u6784\u4EE5\u53CA\u6570\u636E\u9A71\u52A8\u601D\u60F3\u7684\u5E94\u7528\u7B49\u7B49\u3002</p><p>\u4F46\u662F\uFF0C\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u5BF9\u6D4B\u8BD5\u6846\u67B6\u7684\u8981\u6C42\u975E\u5E38\u9AD8\uFF0C\u8FD9\u4E2A\u6846\u67B6\u9664\u4E86\u53EF\u4EE5\u987A\u5229\u88C5\u8F7D\u81EA\u5DF1\u7684\u8F6F\u4EF6\u6A21\u5757\u5916\uFF0C\u8FD8\u5FC5\u987B\u80FD\u88C5\u8F7D\u5176\u4ED6\u76F8\u4E92\u4F9D\u8D56\u7684\u6A21\u5757\uFF0C\u505A\u5230\u88AB\u6D4B\u8F6F\u4EF6\u6A21\u5757\u53EF\u8FD0\u884C\uFF08Runnable\uFF09\u3002</p><p>\u7531\u4E8E\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u4E3B\u8981\u5E94\u7528\u5728\u65E9\u671F\u975E\u4E92\u8054\u7F51\u7684\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\uFF0C\u90A3\u65F6\u5019\u7684\u8F6F\u4EF6\u4EE5\u201C\u5355\u4F53\u201D\u5E94\u7528\u5C45\u591A\uFF0C\u4E00\u4E2A\u8F6F\u4EF6\u5185\u90E8\u5305\u542B\u5927\u91CF\u7684\u529F\u80FD\uFF0C\u6BCF\u4E00\u4E2A\u8F6F\u4EF6\u529F\u80FD\u90FD\u662F\u901A\u8FC7\u4E0D\u540C\u7684\u5185\u90E8\u6A21\u5757\u6765\u5B9E\u73B0\u7684\uFF0C\u90A3\u4E48\u8FD9\u4E9B\u5185\u90E8\u6A21\u5757\u5728\u505A\u96C6\u6210\u7684\u65F6\u5019\uFF0C\u5C31\u9700\u8981\u505A\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u3002</p><p>\u73B0\u5728\u7684\u5F00\u53D1\u7406\u5FF5\u8FFD\u6C42\u7684\u662F\u7CFB\u7EDF\u590D\u6742\u6027\u7684\u89E3\u8026\uFF0C\u4F1A\u53BB\u5C3D\u91CF\u907F\u514D\u201C\u5927\u5355\u4F53\u201D\u5E94\u7528\uFF0C\u91C7\u7528 Web Service \u6216\u8005 RPC \u8C03\u7528\u7684\u65B9\u5F0F\u6765\u534F\u4F5C\u5B8C\u6210\u5404\u4E2A\u8F6F\u4EF6\u529F\u80FD\u3002\u6240\u4EE5\u73B0\u5728\u7684\u8F6F\u4EF6\u4F01\u4E1A\uFF0C\u5C24\u5176\u662F\u4E92\u8054\u7F51\u4F01\u4E1A\uFF0C\u57FA\u672C\u4E0D\u4F1A\u53BB\u505A\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\uFF0C\u6211\u5728\u8FD9\u91CC\u4E5F\u5C31\u4E0D\u518D\u8FDB\u4E00\u6B65\u5C55\u5F00\u4E86\u3002</p><p><strong>Web Service \u6D4B\u8BD5\u7684\u81EA\u52A8\u5316\u6280\u672F</strong></p><p><strong>Web Service \u6D4B\u8BD5\uFF0C\u4E3B\u8981\u662F\u6307 SOAP API \u548C REST API \u8FD9\u4E24\u7C7B API \u6D4B\u8BD5\uFF0C\u6700\u5178\u578B\u7684\u662F\u91C7\u7528 SoapUI \u6216 Postman \u7B49\u7C7B\u4F3C\u7684\u5DE5\u5177\u3002\u4F46\u8FD9\u7C7B\u6D4B\u8BD5\u5DE5\u5177\u57FA\u672C\u90FD\u662F\u754C\u9762\u64CD\u4F5C\u624B\u52A8\u53D1\u8D77 Request \u5E76\u9A8C\u8BC1 Response\uFF0C\u6240\u4EE5\u96BE\u4EE5\u548C CI/CD \u96C6\u6210\uFF0C\u4E8E\u662F\u5C31\u51FA\u73B0\u4E86 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6</strong>\u3002</p><p>\u5982\u679C\u91C7\u7528 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u6765\u5F00\u53D1\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u90A3\u4E48\u8FD9\u4E9B\u6D4B\u8BD5\u7528\u4F8B\u7684\u8868\u73B0\u5F62\u5F0F\u5C31\u662F\u4EE3\u7801\u3002\u4E3A\u4E86\u8BA9\u4F60\u66F4\u76F4\u89C2\u5730\u7406\u89E3\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u662F\u4EC0\u4E48\u6837\u5B50\u7684\uFF0C\u6211\u7ED9\u4F60\u4E3E\u4E00\u4E2A\u201C\u521B\u5EFA\u7528\u6237\u201DAPI \u7684\u4F8B\u5B50\uFF0C\u4F60\u53EA\u9700\u8981\u770B\u4EE3\u7801\u7684\u5927\u81F4\u6B65\u9AA4\u5C31\u53EF\u4EE5\u4E86\uFF0C\u5177\u4F53\u5230\u6BCF\u884C\u4EE3\u7801\u7684\u542B\u4E49\uFF0C\u6211\u4F1A\u5728\u540E\u7EED\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u8BB2\u89E3\u3002 <img src="https://static001.geekbang.org/resource/image/36/06/3679b5816177f9a5624f4fe737850d06.png" alt="\u57FA\u4E8EAPI\u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u6D4B\u8BD5\u7528\u4F8B\u793A\u4F8B\uFF08\u6D4B\u8BD5CreateUser API\uFF09"></p><p><strong>\u5BF9\u4E8E\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7528\u4F8B\uFF0C\u901A\u5E38\u5305\u542B\u4E09\u5927\u6B65\u9AA4</strong>\uFF1A</p><ol><li>\u51C6\u5907 API \u8C03\u7528\u65F6\u9700\u8981\u7684\u6D4B\u8BD5\u6570\u636E\uFF1B</li><li>\u51C6\u5907 API \u7684\u8C03\u7528\u53C2\u6570\u5E76\u53D1\u8D77 API \u7684\u8C03\u7528\uFF1B</li><li>\u9A8C\u8BC1 API \u8C03\u7528\u7684\u8FD4\u56DE\u7ED3\u679C\u3002</li></ol><p>\u76EE\u524D\u6700\u6D41\u884C\u7684 API \u81EA\u52A8\u6D4B\u8BD5\u6846\u67B6\u662F REST Assured\uFF0C\u5B83\u53EF\u4EE5\u65B9\u4FBF\u5730\u53D1\u8D77 Restful API \u8C03\u7528\u5E76\u9A8C\u8BC1\u8FD4\u56DE\u7ED3\u679C\u3002\u5173\u4E8E REST Assured \u7684\u7528\u6CD5\u548C\u4F18\u70B9\uFF0C\u6211\u4F1A\u5728\u540E\u7EED\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u4ECB\u7ECD\u3002</p><p>\u540C\u6837\u5730\uFF0CWeb Service \u6D4B\u8BD5\u201C\u81EA\u52A8\u5316\u201D\u7684\u5185\u6DB5\u4E0D\u4EC5\u4EC5\u5305\u62EC API \u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u81EA\u52A8\u5316\uFF0C\u8FD8\u5305\u62EC\u4EE5\u4E0B\u56DB\u4E2A\u65B9\u9762\uFF1A</p><ol><li>\u6D4B\u8BD5\u811A\u624B\u67B6\u4EE3\u7801\u7684\u81EA\u52A8\u5316\u751F\u6210\uFF1B</li><li>\u90E8\u5206\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u7684\u81EA\u52A8\u751F\u6210\uFF1B</li><li>Response \u9A8C\u8BC1\u7684\u81EA\u52A8\u5316\uFF1B</li><li>\u57FA\u4E8E SoapUI \u6216\u8005 Postman \u7684\u81EA\u52A8\u5316\u811A\u672C\u751F\u6210\u3002</li></ol><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4F1A\u4F9D\u6B21\u4E3A\u4F60\u89E3\u91CA\u8FD9 4 \u4E2A\u65B9\u9762\u4EE3\u8868\u4EC0\u4E48\u542B\u4E49\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u6D4B\u8BD5\u811A\u624B\u67B6\u4EE3\u7801\u7684\u81EA\u52A8\u5316\u751F\u6210</strong></p><p>\u548C\u5355\u5143\u6D4B\u8BD5\u9636\u6BB5\u7684\u7528\u4F8B\u6846\u67B6\u4EE3\u7801\u81EA\u52A8\u751F\u6210\u4E00\u4E2A\u9053\u7406\uFF0C\u4F60\u5728\u5F00\u53D1 API \u6D4B\u8BD5\u7684\u8FC7\u7A0B\u4E2D\u66F4\u5173\u5FC3\u7684\u662F\uFF0C\u5982\u4F55\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u8F93\u5165\u53C2\u6570\u4EE5\u53CA\u7EC4\u5408\uFF0C\u4EE5\u53CA\u5728\u4E0D\u540C\u53C2\u6570\u7EC4\u5408\u60C5\u51B5\u4E0B Response \u7684\u9A8C\u8BC1\uFF0C\u800C\u4F60\u4E0D\u5E0C\u671B\u5C06\u7CBE\u529B\u6D6A\u8D39\u5728\u4EE3\u7801\u5C42\u9762\u5982\u4F55\u7EC4\u7EC7\u6D4B\u8BD5\u7528\u4F8B\u3001\u6D4B\u8BD5\u6570\u636E\u9A71\u52A8\u5982\u4F55\u5B9E\u73B0\u7B49\u975E\u6D4B\u8BD5\u4E1A\u52A1\u4E0A\u3002</p><p>\u8FD9\u65F6\uFF0C\u6D4B\u8BD5\u811A\u624B\u67B6\u4EE3\u7801\u7684\u81EA\u52A8\u751F\u6210\u6280\u672F\u5C31\u6D3E\u4E0A\u7528\u573A\u4E86\u3002\u5B83\u751F\u6210\u7684\u6D4B\u8BD5\u811A\u624B\u67B6\u4EE3\u7801\uFF0C\u901A\u5E38\u5305\u542B\u4E86\u88AB\u6D4B\u8BD5 API \u7684\u8C03\u7528\u3001\u6D4B\u8BD5\u6570\u636E\u4E0E\u811A\u672C\u7684\u5206\u79BB\uFF0C\u4EE5\u53CA Response \u9A8C\u8BC1\u7684\u7A7A\u5B9E\u73B0\u3002</p><p><strong>\u7B2C\u4E8C\uFF0C\u90E8\u5206\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u7684\u81EA\u52A8\u751F\u6210</strong></p><p>\u8FD9\u4E00\u70B9\u548C\u5355\u5143\u6D4B\u8BD5\u7684\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u7684\u81EA\u52A8\u5316\u751F\u6210\u4E5F\u5F88\u7C7B\u4F3C\uFF0C\u552F\u4E00\u4E0D\u540C\u7684\u662F\uFF0C\u5355\u5143\u6D4B\u8BD5\u9488\u5BF9\u7684\u53C2\u6570\u662F\u51FD\u6570\u8F93\u5165\u53C2\u6570\u548C\u51FD\u6570\u5185\u90E8\u8F93\u5165\uFF0C\u800C API \u6D4B\u8BD5\u5BF9\u5E94\u7684\u662F API \u7684\u53C2\u6570\u4EE5\u53CA API \u8C03\u7528\u7684 Payload\u3002\u6570\u636E\u751F\u6210\u7684\u539F\u5219\u540C\u6837\u9075\u5FAA\u8FB9\u754C\u503C\u539F\u5219\u3002</p><p><strong>\u7B2C\u4E09\uFF0CResponse \u9A8C\u8BC1\u7684\u81EA\u52A8\u5316</strong></p><p>\u5BF9\u4E8E API \u8C03\u7528\u8FD4\u56DE\u7ED3\u679C\u7684\u9A8C\u8BC1\uFF0C\u901A\u5E38\u5173\u6CE8\u7684\u70B9\u662F\u8FD4\u56DE\u72B6\u6001\u7801\uFF08status code\uFF09\u3001Scheme \u7ED3\u6784\u4EE5\u53CA\u5177\u4F53\u7684\u5B57\u6BB5\u503C\u3002\u5982\u679C\u4F60\u5199\u8FC7\u8FD9\u79CD\u7C7B\u578B\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u90A3\u4F60\u5C31\u4F1A\u77E5\u9053\u5B57\u6BB5\u503C\u7684\u9A8C\u8BC1\u76F8\u5F53\u9EBB\u70E6\uFF0C\u53EA\u6709\u90A3\u4E9B\u4F60\u660E\u786E\u5199\u4E86 assert \u7684\u5B57\u6BB5\u624D\u4F1A\u88AB\u9A8C\u8BC1\uFF0C\u4F46\u662F\u901A\u5E38\u4F60\u4E0D\u53EF\u80FD\u9488\u5BF9\u6240\u6709\u7684\u5B57\u6BB5\u90FD\u5199 assert\uFF0C\u8FD9\u65F6\u5C31\u9700\u8981 Response \u9A8C\u8BC1\u7684\u81EA\u52A8\u5316\u6280\u672F\u4E86\u3002</p><p><strong>Response \u9A8C\u8BC1\u81EA\u52A8\u5316\u7684\u6838\u5FC3\u601D\u60F3\u662F\u81EA\u52A8\u6BD4\u8F83\u4E24\u6B21\u76F8\u540C API \u8C03\u7528\u7684\u8FD4\u56DE\u7ED3\u679C\uFF0C\u5E76\u81EA\u52A8\u8BC6\u522B\u51FA\u6709\u5DEE\u5F02\u7684\u5B57\u6BB5\u503C\uFF0C\u6BD4\u8F83\u8FC7\u7A0B\u53EF\u4EE5\u901A\u8FC7\u89C4\u5219\u914D\u7F6E\u53BB\u6389\u8BF8\u5982\u65F6\u95F4\u6233\u3001\u4F1A\u8BDD ID\uFF08Session ID\uFF09\u7B49\u52A8\u6001\u503C</strong>\u3002 \u8FD9\u90E8\u5206\u5185\u5BB9\uFF0C\u6211\u4F1A\u5728\u540E\u7EED\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u8BB2\u89E3\u3002</p><p><strong>\u7B2C\u56DB\uFF0C\u57FA\u4E8E SoapUI \u6216\u8005 Postman \u7684\u81EA\u52A8\u5316\u811A\u672C\u751F\u6210</strong></p><p>\u4F60\u5728\u4F7F\u7528 SoapUI \u6216\u8005 Postman \u7B49\u5DE5\u5177\u8FDB\u884C Web Service \u6D4B\u8BD5\u65F6\uFF0C\u5DF2\u7ECF\u5728\u8FD9\u4E9B\u5DE5\u5177\u91CC\u9762\u79EF\u7D2F\u4E86\u5F88\u591A\u6D4B\u8BD5\u7528\u4F8B\u3002\u90A3\u4E48\uFF0C\u5728\u5F15\u5165\u4E86\u57FA\u4E8E\u4EE3\u7801\u5B9E\u73B0\u7684 API \u6D4B\u8BD5\u6846\u67B6\u4E4B\u540E\uFF0C\u5C31\u610F\u5473\u7740\u9700\u8981\u628A\u8FD9\u4E9B\u6D4B\u8BD5\u7528\u4F8B\u90FD\u7528\u4EE3\u7801\u7684\u65B9\u5F0F\u91CD\u5199\u4E00\u904D\uFF0C\u800C\u8FD9\u989D\u5916\u7684\u5DE5\u4F5C\u91CF\u662F\u5F88\u96BE\u88AB\u63A5\u53D7\u7684\u3002</p><p>\u6211\u7684\u5EFA\u8BAE\u662F\uFF0C\u5F00\u53D1\u4E00\u4E2A\u81EA\u52A8\u5316\u4EE3\u7801\u8F6C\u6362\u751F\u6210\u5DE5\u5177\u3002\u8FD9\u4E2A\u5DE5\u5177\u7684\u8F93\u5165\u662F SoapUI \u6216\u8005 Postman \u7684\u6D4B\u8BD5\u7528\u4F8B\u5143\u6570\u636E\uFF08\u5373\u6D4B\u8BD5\u7528\u4F8B\u7684 JSON \u5143\u6587\u4EF6\uFF09\uFF0C\u8F93\u51FA\u662F\u7B26\u5408 API \u6D4B\u8BD5\u6846\u67B6\u89C4\u8303\u7684\u57FA\u4E8E\u4EE3\u7801\u5B9E\u73B0\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002\u8FD9\u6837\u4E00\u6765\uFF0C\u539F\u672C\u7684\u6D4B\u8BD5\u7528\u4F8B\u79EF\u7D2F\u53EF\u4EE5\u76F4\u63A5\u8F6C\u6362\u6210\u5728 CI/CD \u4E0A\u53EF\u4EE5\u76F4\u63A5\u63A5\u5165\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u5BF9\u4E8E\u65B0\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u8FD8\u53EF\u4EE5\u7EE7\u7EED\u7528 SoapUI \u6216\u8005 Postman \u505A\u521D\u6B65\u7684\u6D4B\u8BD5\u9A8C\u8BC1\uFF0C\u521D\u6B65\u9A8C\u8BC1\u6CA1\u6709\u95EE\u9898\u540E\uFF0C\u76F4\u63A5\u8F6C\u6362\u6210\u7B26\u5408 API \u6D4B\u8BD5\u6846\u67B6\u89C4\u8303\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002\u5BF9\u4E8E\u590D\u6742\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u4E5F\u53EF\u4EE5\u76F4\u63A5\u57FA\u4E8E\u4EE3\u7801\u6765\u5B9E\u73B0\uFF0C\u800C\u4E14\u7075\u6D3B\u6027\u4F1A\u66F4\u597D\u3002</p><p><strong>GUI \u6D4B\u8BD5\u7684\u81EA\u52A8\u5316\u6280\u672F</strong></p><p>GUI \u6D4B\u8BD5\u7684\u81EA\u52A8\u5316\u6280\u672F\u53EF\u80FD\u662F\u4F60\u6700\u719F\u6089\u7684\uFF0C\u4E5F\u662F\u53D1\u5C55\u65F6\u95F4\u6700\u957F\u3001\u5E94\u7528\u6700\u5E7F\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\u3002\u5B83\u7684\u6838\u5FC3\u601D\u60F3\u662F\uFF0C\u57FA\u4E8E\u9875\u9762\u5143\u7D20\u8BC6\u522B\u6280\u672F\uFF0C\u5BF9\u9875\u9762\u5143\u7D20\u8FDB\u884C\u81EA\u52A8\u5316\u64CD\u4F5C\uFF0C\u4EE5\u6A21\u62DF\u5B9E\u9645\u7EC8\u7AEF\u7528\u6237\u7684\u884C\u4E3A\u5E76\u9A8C\u8BC1\u8F6F\u4EF6\u529F\u80FD\u7684\u6B63\u786E\u6027\u3002</p><p><em>\u76EE\u524D\uFF0CGUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u4E3B\u8981\u5206\u4E3A\u4E24\u5927\u65B9\u5411\uFF0C\u4F20\u7EDF Web \u6D4F\u89C8\u5668\u548C\u79FB\u52A8\u7AEF\u539F\u751F\u5E94\u7528\uFF08Native App\uFF09\u7684 GUI \u81EA\u52A8\u5316\u3002\u867D\u7136\u4E8C\u8005\u91C7\u7528\u7684\u5177\u4F53\u6280\u672F\u5DEE\u522B\u5F88\u5927\uFF0C\u4F46\u662F\u7528\u4F8B\u8BBE\u8BA1\u7684\u601D\u8DEF\u7C7B\u4F3C</em>\u3002</p><ul><li>\u5BF9\u4E8E\u4F20\u7EDF Web \u6D4F\u89C8\u5668\u7684 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u4E1A\u5185\u4E3B\u6D41\u7684\u5F00\u6E90\u65B9\u6848\u91C7\u7528 Selenium\uFF0C\u5546\u4E1A\u65B9\u6848\u91C7\u7528 Micro Focus \u7684 UFT\uFF08\u524D\u8EAB\u662F HP \u7684 QTP\uFF09\uFF1B</li><li>\u5BF9\u4E8E\u79FB\u52A8\u7AEF\u539F\u751F\u5E94\u7528\uFF0C\u901A\u5E38\u91C7\u7528\u4E3B\u6D41\u7684 Appium\uFF0C\u5B83\u5BF9 iOS \u73AF\u5883\u96C6\u6210\u4E86 XCUITest\uFF0C\u5BF9 Android \u73AF\u5883\u96C6\u6210\u4E86 UIAutomator \u548C Espresso\u3002</li></ul><p>\u8FD9\u90E8\u5206\u5185\u5BB9\uFF0C\u6211\u4F1A\u5728\u540E\u7EED\u7684\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u5C55\u5F00\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u6211\u7ED9\u4F60\u68B3\u7406\u4E86\u8F6F\u4EF6\u7814\u53D1\u751F\u547D\u5468\u671F\u5404\u4E2A\u9636\u6BB5\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\uFF0C\u5305\u62EC\u5355\u5143\u6D4B\u8BD5\u3001\u4EE3\u7801\u7EA7\u96C6\u6210\u6D4B\u8BD5\u3001Web Service \u6D4B\u8BD5\u548C GUI \u6D4B\u8BD5\u7684\u81EA\u52A8\u5316\u6280\u672F\uFF0C\u5E76\u7ED9\u4F60\u5F52\u7EB3\u4E86\u6BCF\u4E00\u7C7B\u6280\u672F\u7684\u6838\u5FC3\u65B9\u6CD5\u548C\u5E94\u7528\u573A\u666F\u3002</p><p>\u6211\u5E0C\u671B\u4F60\u901A\u8FC7\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u53EF\u4EE5\u5148\u5BF9\u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u5168\u5C40\u6709\u4E00\u4E2A\u6BD4\u8F83\u6E05\u6670\u7684\u8BA4\u8BC6\uFF0C\u7136\u540E\u5728\u540E\u7EED\u7684\u6587\u7AE0\u4E2D\u6211\u8FD8\u4F1A\u9488\u5BF9\u8FD9\u4E9B\u6280\u672F\u5C55\u5F00\u8BA8\u8BBA\uFF0C\u5E76\u7ED9\u4F60\u5206\u4EAB\u4E00\u4E9B\u76F8\u5E94\u7684\u5B9E\u9645\u6848\u4F8B\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u73B0\u5728\u6240\u5728\u7684\u516C\u53F8\uFF0C\u662F\u5426\u5B9E\u884C\u4EE3\u7801\u7EA7\u6D4B\u8BD5\uFF0C\u7528\u5230\u4E86\u54EA\u4E9B\u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\uFF1F</p>',65);function t(r,n){return e}var g=p(o,[["render",t],["__file","05.html.vue"]]);export{g as default};
